css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { min-height: 100vh; display: flex; align-items: center; justify-content: center; background: radial-gradient(ellipse at top, #1c0f2e 0%, #070b18 60%); padding: 24px; }
.card { width: 100%; max-width: 420px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 24px; overflow: hidden; backdrop-filter: blur(20px); box-shadow: 0 30px 60px rgba(0,0,0,0.4); }
.cover { height: 100px; background: linear-gradient(135deg, #a855f7, #6366f1); }
.avatar-wrap { position: relative; width: 92px; margin: -46px auto 0; }
.avatar { width: 92px; height: 92px; border-radius: 50%; background: linear-gradient(135deg, #a855f7, #ec4899); display: flex; align-items: center; justify-content: center; color: white; font-size: 30px; font-weight: 700; border: 4px solid #14101f; }
.edit-avatar { position: absolute; bottom: 0; right: -4px; width: 28px; height: 28px; border-radius: 50%; background: #a855f7; border: 3px solid #14101f; color: white; display: flex; align-items: center; justify-content: center; cursor: pointer; }
.info { text-align: center; padding: 14px 24px 0; }
.info h1 { color: white; font-size: 22px; font-weight: 700; }
.role { color: rgba(255,255,255,0.5); font-size: 13px; margin-top: 4px; }
.stats { display: flex; justify-content: center; gap: 36px; padding: 22px 24px; }
.stat { text-align: center; }
.stat .num { display: block; color: white; font-size: 18px; font-weight: 700; }
.stat .label { color: rgba(255,255,255,0.4); font-size: 12px; margin-top: 2px; }
.actions { display: flex; gap: 10px; padding: 0 24px 20px; }
.btn-primary { flex: 1; padding: 13px; border: none; border-radius: 12px; background: linear-gradient(135deg, #a855f7, #6366f1); color: white; font-size: 14px; font-weight: 700; cursor: pointer; box-shadow: 0 10px 25px rgba(168,85,247,0.3); }
.btn-icon { width: 46px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: white; cursor: pointer; display: flex; align-items: center; justify-content: center; }
.btn-secondary { flex: 1; padding: 13px; border: 1px solid rgba(255,255,255,0.12); border-radius: 12px; background: transparent; color: white; font-size: 14px; font-weight: 600; cursor: pointer; }
.bio { padding: 0 24px 20px; color: rgba(255,255,255,0.6); font-size: 13.5px; line-height: 1.6; text-align: center; }
.badges { display: flex; flex-wrap: wrap; gap: 8px; justify-content: center; padding: 0 24px 28px; }
.badge { padding: 6px 14px; border-radius: 999px; background: rgba(168,85,247,0.15); color: #c084fc; font-size: 12px; font-weight: 600; }
.form { padding: 0 24px 20px; display: flex; flex-direction: column; gap: 6px; }
.form.hidden { display: none; }
.form label { color: rgba(255,255,255,0.6); font-size: 12px; font-weight: 600; margin-top: 8px; }
.form input, .form textarea { width: 100%; padding: 11px 14px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: white; font-size: 14px; outline: none; font-family: inherit; resize: none; }
.form input:focus, .form textarea:focus { border-color: #a855f7; }
.form-actions { display: flex; gap: 10px; margin-top: 12px; }

js:
const editForm = document.getElementById('editForm');
const bioSection = document.getElementById('bioSection');
const badges = document.querySelector('.badges');
const actions = document.querySelector('.actions');

function toggleEdit() {
  const isHidden = editForm.classList.contains('hidden');
  editForm.classList.toggle('hidden');
  bioSection.style.display = isHidden ? 'none' : 'block';
  badges.style.display = isHidden ? 'none' : 'flex';
  actions.style.display = isHidden ? 'none' : 'flex';
}

function save() {
  toggleEdit();
}
